const Header = ({course}) => {
  return (
    <div>
      <h1>
        {course.course.name}
      </h1>
    </div>
  )
}

const Part = ({part}) => {
  return (
    <p>
    {part.name} {part.exercises}
    </p>
  )
}

const Content = (props) => {
  return (
    <div>
      {props.parts.map(part => (<Part key = {part.id} part = {part} />))}
    </div>
  )
}


const Course = (courses) => {
  return courses.map((course) =>
    <div>
      <Header course = {course}/>
      <Content parts = {course.course.parts}/>
      <Total total = {course.course.parts} />
    </div>
  )
}



const Total = (props) => {
  const totalExercises = props.total.map(exerciseAmount => exerciseAmount.exercises)
  const totalSum = totalExercises.reduce((a,s) => a+s )
  return (
    <div>
      <p>
        total of {totalSum} exercises
      </p>
    </div>
  )
}


const App = () => {
  const courses = [
    {
      name: 'Half Stack application development',
      id: 1,
      parts: [
        {
          name: 'Fundamentals of React',
          exercises: 10,
          id: 1
        },
        {
          name: 'Using props to pass data',
          exercises: 7,
          id: 2
        },
        {
          name: 'State of a component',
          exercises: 14,
          id: 3
        },
        {
          name: 'Redux',
          exercises: 11,
          id: 4
        }
      ]
    }, 
    {
      name: 'Node.js',
      id: 2,
      parts: [
        {
          name: 'Routing',
          exercises: 3,
          id: 1
        },
        {
          name: 'Middlewares',
          exercises: 7,
          id: 2
        }
      ]
    }
  ]

  return <Course courses={courses} />
}

export default App
